<template>
    <input :value="modelValue" @input="updateInput">
</template>

<script>
export default {
    props: {
        modelValue: [String, Number]
    },

    methods: {
        updateInput(event) {
            this.$emit("update:modelValue", event.target.value)
        }
    }
}
</script>

<style>
    input {
        border: 2px solid teal;
    }
</style>