<template>
    <div class="pagination">
        <div v-for="page in pages"
        :key="page" 
        class="number"
        :class="{
            'current_number': page === currentPage
        }"
        @click="getPage(page)"
        >{{ page }}
        </div>
    </div>
</template>

<script>
export default {
    props: {
        currentPage: Number,
        pages: Number,
    },
    methods: {
        getPage(page) {
            this.$emit("getPage", page)
        }
    }
}
</script>

<style>
    .pagination {
        display: flex;
        flex-direction: row;
        width: 100%;
        margin: 5px
    }
    .number {
        padding: 10px;
        border:  1px solid black;
    }
    .current_number {
        border:  2px solid teal;
    }
</style>