<template>
    <Dialog :show="this.show"><PostForm @create="createPost"></PostForm></Dialog>
    <Input v-model="searchQuery" placeholder="Поиск ..."></Input>
    <Select v-model="selectedSort" :options="sortOptions"></Select>
    <PostList :posts="searchPost" @remove="deletePost(post)" v-if="!isPostsLoading"></PostList>
    <div v-else>Идет загрузка ...</div>
    <div class="observer" ref="observer"></div>
    <!-- <Pagination :pages="totalPages"
    :currentPage="page"
    @getPage="changePage"></Pagination> -->
</template>

<script>
import PostList from './components/PostList.vue';
import PostForm from './components/PostForm.vue';
import Dialog from './components/UI/Dialog.vue';
import axios from 'axios';
import Button from './components/UI/Button.vue';
import Select from './components/UI/Select.vue';
import Input from './components/UI/Input.vue';
import Pagination from './components/UI/Pagination.vue';

export default {
    components: {
        PostList, PostForm, Dialog, Button, Select, Input, Pagination
    },

    data() {
        return {
            posts: [],
            show: true,
            isPostsLoading:  false,
            selectedSort: '',
            sortOptions: [
                {value:'title', name:'по названию'},
                {value:'body', name:'по содержанию'},
            ],
            searchQuery: '',
            page: 1,
            limit: 10,
            totalPages: 0
        }
    },
    methods: {
        createPost(post) {
            this.posts.push(post)
            this.show = false
        },
        deletePost(post) {
            this.posts = this.posts.filter(p => p.id !== post.id)
        },
        async fetchPosts() {
            // this.isPostsLoading = true
            setTimeout(async() => {
                const response = await axios.get("https://jsonplaceholder.typicode.com/posts", {
                    params: {
                        _page: this.page,
                        _limit: this.limit,   
                    }
                })
                this.totalPages = Math.ceil(response.headers["x-total-count"] / this.limit)
                this.posts = [...  this.posts, ...response.data]
                // this.isPostsLoading = false
            }, 1000)
            
        },
        // changePage(page) {
        //     this.page = page
        //     this.fetchPosts( )
        // }
    },
    mounted() {
        this.fetchPosts();

        const options = {
        rootMargin: "0px",
        threshold: 1.0,
        };
        const callback = (entries, observer) => {
            if (entries[0].isIntersecting) {
                this.page += 1
                this.fetchPosts()
            }
        };
        const observer = new IntersectionObserver(callback, options);
        observer.observe(this.$refs.observer)
    },
    watch: {
        selectedSort(newValue) {
            this.posts.sort((post1, post2) => {
                return post1[newValue]?.localeCompare(post2[newValue])
            })
        }
    },
    computed: {
        searchPost() {
            return this.posts.filter(post => post.title.includes(this.searchQuery))
        }
    }
}
</script>

<style scoped>
    .observer {
        background-color: rgba(31, 135, 31, 0.5);
        width: 100%;
        height: 20px
    }
</style>