<template>
    <form @submit.prevent>
        <Input
         type="text"
         placeholder="Название"
         v-model="post.title"
        ></Input>

        <Input
         type="text"
         placeholder="Контент"
         v-model="post.body"
         ></Input>

        <Button @click="createPost">Отправить</Button>
    </form>
</template>

<script>
import Button from './UI/Button.vue';
import Input from './UI/Input.vue';

export default {
    components: {
        Button, Input
    },

    data() {
        return {
            post: {
                body: '',
                title: ''
            }
        }
    },

    methods: {
        createPost() {
            this.post.id = Math.random()
            this.$emit('create', this.post)
            this.post = {
                title: '',
                body: ''
            }
        }
    }
}
</script>

<style scoped>
    button {
        border: 2px solid teal;
        background-color: none;
    }
    * {
        padding: 10px;
        margin: 10px
    }
    
    
</style>